    match health_probe(&cfg) {
        Ok(()) => Surface::Explore { cfg, root: root.to_path_buf() },
        Err(e) => {
            eprintln!("grove serve: explore provider unhealthy ({e}); falling back to standard structural surface");
            Surface::Standard
        }
    }
}

